agent_output:
{
  "domain_analysis": {
    "business_context": "A logistics platform managing parcel delivery lifecycle — from shipment creation through transit to final delivery — with weight-based pricing tiers.",
    "bounded_context": "Shipment Management",
    "ubiquitous_language": [
      { "term": "Shipment", "definition": "A domain entity representing a parcel moving from a pickup address to a delivery address, progressing through defined lifecycle states." },
      { "term": "Pickup Address", "definition": "The origin location where a parcel is collected. Required at shipment creation." },
      { "term": "Delivery Address", "definition": "The destination location where a parcel must be delivered. Required at shipment creation." },
      { "term": "Shipment State", "definition": "The lifecycle stage of a shipment. Valid states: Pending, In Transit, Delivered. Transitions are strictly forward-only." },
      { "term": "Weight", "definition": "The physical mass of the parcel in kilograms. Must be positive and cannot exceed 1000 kg." },
      { "term": "Weight Bracket", "definition": "A pricing classification derived from parcel weight: Standard (0–10 kg], Heavy (10–50 kg], Freight (>50 kg)." },
      { "term": "Standard", "definition": "Weight bracket for parcels weighing more than 0 kg up to and including 10 kg." },
      { "term": "Heavy", "definition": "Weight bracket for parcels weighing more than 10 kg up to and including 50 kg." },
      { "term": "Freight", "definition": "Weight bracket for parcels weighing more than 50 kg up to and including 1000 kg." }
    ]
  },

  "business_rules": [
    {
      "id": "BR-1",
      "rule": "A shipment can only be created when both a pickup address and a delivery address are provided.",
      "invariant": true,
      "invariant_justification": "A shipment without both endpoints is logically meaningless — it cannot be routed, priced, or fulfilled. This is a data integrity constraint.",
      "testable_assertion": "Any attempt to create a shipment with a missing or empty pickup address or delivery address MUST be rejected."
    },
    {
      "id": "BR-2",
      "rule": "Shipment state transitions are strictly forward-only: Pending → In Transit → Delivered. No backward transitions are permitted.",
      "invariant": true,
      "invariant_justification": "Backward transitions would corrupt downstream processes (billing, tracking notifications, driver dispatch). Once a parcel is physically in transit, the real world cannot be rewound. This is a state integrity constraint.",
      "testable_assertion": "A shipment in state 'In Transit' MUST NOT transition to 'Pending'. A shipment in state 'Delivered' MUST NOT transition to any other state."
    },
    {
      "id": "BR-3",
      "rule": "Delivered is a terminal state — no further state changes are allowed on a delivered shipment.",
      "invariant": true,
      "invariant_justification": "Delivery represents a completed physical handoff. Changing state after delivery would corrupt audit trails, billing records, and proof-of-delivery. This is a data consistency invariant.",
      "testable_assertion": "Any attempt to change the state of a Delivered shipment MUST be rejected, regardless of the target state."
    },
    {
      "id": "BR-4",
      "rule": "Shipment weight must be strictly positive (greater than zero).",
      "invariant": true,
      "invariant_justification": "A zero or negative weight is physically impossible for a real parcel and would break weight-bracket pricing. This is a physical constraint.",
      "testable_assertion": "Any shipment with weight <= 0 MUST be rejected at creation and at any update."
    },
    {
      "id": "BR-5",
      "rule": "Shipment weight must not exceed 1000 kg.",
      "invariant": false,
      "invariant_justification": "The 1000 kg cap is a business policy reflecting current fleet/infrastructure limits. A VP could raise this ceiling if the company acquires heavier-capacity vehicles or partners with a freight carrier.",
      "testable_assertion": "Any shipment with weight > 1000 kg MUST be rejected."
    },
    {
      "id": "BR-6",
      "rule": "Weight bracket classification: Standard for weight in (0, 10] kg, Heavy for weight in (10, 50] kg, Freight for weight in (50, 1000] kg.",
      "invariant": false,
      "invariant_justification": "Bracket thresholds and names are pricing policy — they can be adjusted by business decision without corrupting system integrity.",
      "testable_assertion": "A 10 kg parcel MUST be classified as Standard. A 10.01 kg parcel MUST be classified as Heavy. A 50 kg parcel MUST be classified as Heavy. A 50.01 kg parcel MUST be classified as Freight."
    }
  ],

  "acceptance_criteria": [
    {
      "id": "AC-1",
      "given": "A request to create a shipment with a valid pickup address and a valid delivery address",
      "when": "The shipment is created",
      "then": "The shipment is persisted in Pending state with both addresses recorded"
    },
    {
      "id": "AC-2",
      "given": "A request to create a shipment with a missing pickup address",
      "when": "The creation is attempted",
      "then": "The system rejects the request with a validation error indicating pickup address is required"
    },
    {
      "id": "AC-3",
      "given": "A request to create a shipment with a missing delivery address",
      "when": "The creation is attempted",
      "then": "The system rejects the request with a validation error indicating delivery address is required"
    },
    {
      "id": "AC-4",
      "given": "A shipment in Pending state",
      "when": "A transition to In Transit is requested",
      "then": "The shipment state changes to In Transit"
    },
    {
      "id": "AC-5",
      "given": "A shipment in In Transit state",
      "when": "A transition to Pending is requested",
      "then": "The system rejects the transition and the shipment remains In Transit"
    },
    {
      "id": "AC-6",
      "given": "A shipment in In Transit state",
      "when": "A transition to Delivered is requested",
      "then": "The shipment state changes to Delivered"
    },
    {
      "id": "AC-7",
      "given": "A shipment in Delivered state",
      "when": "Any state transition is requested",
      "then": "The system rejects the transition and the shipment remains Delivered"
    },
    {
      "id": "AC-8",
      "given": "A shipment creation request with weight of 0 kg or a negative value",
      "when": "The creation is attempted",
      "then": "The system rejects the request with a validation error indicating weight must be positive"
    },
    {
      "id": "AC-9",
      "given": "A shipment creation request with weight exceeding 1000 kg",
      "when": "The creation is attempted",
      "then": "The system rejects the request with a validation error indicating weight exceeds the maximum"
    },
    {
      "id": "AC-10",
      "given": "A shipment with weight of 7 kg",
      "when": "The weight bracket is determined",
      "then": "The shipment is classified as Standard"
    },
    {
      "id": "AC-11",
      "given": "A shipment with weight of 25 kg",
      "when": "The weight bracket is determined",
      "then": "The shipment is classified as Heavy"
    },
    {
      "id": "AC-12",
      "given": "A shipment with weight of 75 kg",
      "when": "The weight bracket is determined",
      "then": "The shipment is classified as Freight"
    },
    {
      "id": "AC-13",
      "given": "A shipment in Pending state",
      "when": "A transition directly to Delivered is requested",
      "then": "The system rejects the transition — a shipment must pass through In Transit before reaching Delivered"
    }
  ],

  "edge_cases": [
    { "scenario": "Weight is exactly 10 kg", "expected_behavior": "Classified as Standard (upper boundary inclusive for Standard bracket)." },
    { "scenario": "Weight is exactly 50 kg", "expected_behavior": "Classified as Heavy (upper boundary inclusive for Heavy bracket)." },
    { "scenario": "Weight is exactly 1000 kg", "expected_behavior": "Accepted and classified as Freight (at the policy maximum)." },
    { "scenario": "Weight is 1000.01 kg", "expected_behavior": "Rejected — exceeds the 1000 kg maximum." },
    { "scenario": "Weight is 0.001 kg (near-zero positive)", "expected_behavior": "Accepted — weight is positive. Classified as Standard." },
    { "scenario": "Pending shipment attempts direct transition to Delivered (skipping In Transit)", "expected_behavior": "Rejected — state transitions must follow the defined forward-only sequence. Pending → Delivered skips In Transit." },
    { "scenario": "Delivered shipment receives a second delivery confirmation", "expected_behavior": "Rejected — Delivered is terminal; idempotent delivery events should be safe but must not alter state." },
    { "scenario": "Pickup address and delivery address are identical", "expected_behavior": "Spec does not prohibit this. Likely valid edge case but should be flagged for business review — see escalations." },
    { "scenario": "Weight is updated after shipment is In Transit", "expected_behavior": "Spec is silent on weight mutability after creation. If allowed, bracket reclassification and re-pricing must occur. See escalations." }
  ],

  "business_impact": {
    "financial": "Weight brackets directly drive pricing. Miscategorization at bracket boundaries (10 kg, 50 kg) causes revenue leakage or customer overcharge. Correct enforcement of the 1000 kg ceiling prevents accepting shipments the fleet cannot physically handle.",
    "operational": "Forward-only state machine prevents dispatch confusion, duplicate pickups, and phantom re-routing. Terminal Delivered state protects proof-of-delivery integrity and triggers downstream settlement.",
    "user": "Customers get reliable tracking with no confusing backward status changes. Clear weight rejection messages prevent frustration. Transparent bracket pricing builds trust.",
    "risk": "Primary risk is bracket boundary ambiguity (inclusive vs exclusive at 10 kg and 50 kg) — if implemented inconsistently across services, pricing disputes will arise. Secondary risk: spec silence on Pending → Delivered skip could allow a code path that bypasses transit tracking entirely.",
    "stakeholders_affected": [
