    "high_confidence_areas": [
      "Forward-only state machine (Pending → In Transit → Delivered)",
      "Delivered is terminal — no further transitions",
      "Weight must be positive and <= 1000 kg",
      "Three weight brackets exist: Standard, Heavy, Freight",
      "Both addresses required at creation"
    ],
    "low_confidence_areas": [
      "Bracket boundary inclusivity (is 10 kg Standard or Heavy?)",
      "Whether Pending → Delivered direct skip is allowed or forbidden",
      "Whether weight can be modified after shipment creation",
      "Address validation depth (format, geocoding, same-address allowed?)"
    ],
    "assumptions": [
      "Bracket boundaries are upper-inclusive: Standard = (0, 10], Heavy = (10, 50], Freight = (50, 1000] — industry standard convention",
      "Pending → Delivered skip is NOT allowed — In Transit represents a real physical event (pickup) that must occur before delivery",
      "Weight is immutable after creation — changing weight mid-transit would require re-pricing and audit trail, which the spec does not mention",
      "Shipments are created in Pending state by default"
    ]
